    val sums = mutableMapOf<Long, Int>()

    // We need to iterate over all pairs (a, b) such that a^3 + b^3 <= n and 1 <= a <= b.

    // Determine the maximum possible value for 'a' and 'b'.
    // Since a <= b, we have a^3 + b^3 <= 2 * b^3 <= n.
    // So, b^3 <= n/2. b <= cbrt(n/2).
    // For simplicity and to avoid floating-point precision issues for the limit,
    // we can iterate 'a' up to a limit where a^3 < n, and then 'b' up to where a^3 + b^3 <= n.

    // Maximum possible value for b (when a=1). b^3 <= n - 1.
    // We can estimate an upper bound for b. Since n <= 10^9, the maximum b is around 1000.
    // (1000^3 = 10^9).
    var maxB = 0L
    var temp = 1L
    while (temp * temp * temp <= n) {
        maxB = temp
        temp++
    }
    maxB-- // maxB is the largest integer such that maxB^3 <= n

    val results = mutableListOf<Long>()

    // Iterate through 'a'
